mapper.select:
SELECT po.*, purchaser.login_name AS purchaser_name, auditor.login_name AS auditor_name FROM purchase_order po LEFT JOIN sys_user purchaser ON po.purchaser_id = purchaser.id AND purchaser.is_deleted = 0 LEFT JOIN sys_user auditor ON po.auditor_id = auditor.id AND auditor.is_deleted = 0 WHERE po.is_deleted = 0
AND po.supplier_name LIKE CONCAT('%', #{supplierName}, '%')
AND po.order_status = #{orderStatus}
AND po.create_time >= #{createTimeStart}
AND po.create_time <= #{createTimeEnd}
ORDER BY po.create_time DESC
